968:     /// The scale to use when displaying this [`WebViewRenderer`] in WebRender
969:     /// including both viewport scale (page zoom and hidpi scale) as well as any
970:     /// pinch zoom applied. This is based on the latest display list received,
971:     /// as page zoom changes are applied asynchronously and the rendered view
972:     /// should reflect the latest display list.
973:     pub(crate) fn device_pixels_per_page_pixel(&self) -> Scale<f32, CSSPixel, DevicePixel> {
974:         let viewport_scale = self
975:             .root_pipeline_id
976:             .and_then(|pipeline_id| self.pipelines.get(&pipeline_id))
977:             .and_then(|pipeline| pipeline.viewport_scale)
978:             .unwrap_or_else(|| self.page_zoom * self.hidpi_scale_factor);
979:         viewport_scale * self.pinch_zoom.zoom_factor()
980:     }
